const response = $.steps.listEmails.response || {};
const messages = response.data?.messages || response.messages || [];
let emailData = '';
const emailList = [];

messages.slice(0, $.input.maxEmails || 5).forEach(function(msg, i) {
  const headers = msg.payload?.headers || [];
  let subject = '';
  let from = '';
  let to = '';
  headers.forEach(function(h) {
    if (h.name === 'Subject') subject = h.value || '';
    if (h.name === 'From') from = h.value || '';
    if (h.name === 'To') to = h.value || '';
  });
  const snippet = msg.snippet || '';
  emailData += '=== EMAIL ' + (i + 1) + ' ===\n';
  emailData += 'From: ' + from + '\n';
  emailData += 'Subject: ' + subject + '\n';
  emailData += 'Content: ' + snippet + '\n\n';
  emailList.push({ index: i + 1, from: from, subject: subject, snippet: snippet, to: to });
});

return { emailData: emailData, emailList: emailList, emailCount: emailList.length };

const data = $.steps.extractEmails.output;
const tone = $.input.replyTone || 'professional and helpful';
const samples = $.input.sampleReplies || '';
const name = $.input.senderName || '';

let prompt = 'You are an AI email assistant. Generate professional replies to the following emails.\n\n';
prompt += 'REPLY TONE: ' + tone + '\n';
if (name) prompt += 'SENDER NAME: ' + name + '\n';
if (samples) prompt += 'SAMPLE REPLIES FOR STYLE REFERENCE:\n' + samples + '\n\n';
prompt += 'EMAILS TO REPLY TO:\n' + data.emailData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Generate a thoughtful reply for each email\n';
prompt += '- Match the specified tone and style\n';
prompt += '- Keep replies concise but complete\n';
prompt += '- Address the sender by name when possible\n';
prompt += '- Include appropriate greetings and sign-offs\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "replies": [\n';
prompt += '    { "emailIndex": 1, "to": "recipient email", "subject": "Re: original subject", "reply": "full reply text", "confidence": "high|medium|low" }\n';
prompt += '  ],\n';
prompt += '  "summary": "brief summary of actions taken"\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiReplies.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { replies: [], summary: raw.slice(0, 300) }; }

const ai = $.steps.parseAI.output;
const emailList = $.steps.extractEmails.output.emailList;
const replies = ai.replies || [];
const toSend = [];

replies.forEach(function(r) {
  const idx = (r.emailIndex || 1) - 1;
  const original = emailList[idx] || {};
  const recipientEmail = (r.to || original.from || '').replace(/.*</, '').replace(/>.*/, '').trim();
  if (recipientEmail && recipientEmail.indexOf('@') > 0) {
    toSend.push({
      to: recipientEmail,
      subject: r.subject || 'Re: ' + (original.subject || ''),
      body: r.reply || '',
      confidence: r.confidence || 'medium'
    });
  }
});

return { toSend: toSend, count: toSend.length };

const ai = $.steps.parseAI.output;
const sent = $.steps.prepareReplies.output;
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Email Replies Sent', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Replies Generated:* ' + sent.count + '\n' + (ai.summary || '') } });
blocks.push({ type: 'divider' });

const toSend = sent.toSend || [];
toSend.slice(0, 5).forEach(function(r) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*To:* ' + r.to + '\n*Subject:* ' + r.subject + '\n*Confidence:* ' + r.confidence } });
});

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Claude AI' }] });
const fallbackText = 'Email Replies: ' + sent.count + ' replies sent via AI';
return { blocks, fallbackText };
